1	"use client";
2	
3	import { useCallback, useEffect, useRef, useState } from "react";
4	import { useShallow } from "zustand/react/shallow";
5	import { useChatStream } from "@/features/chat/hooks/useChatStream";
6	import type { IMessage } from "@/lib/db/chatDb";
7	import { useChatStore } from "@/stores/chatStore";
8	import type { MessageType } from "@/types/features/convoTypes";
9	
10	export interface UseOnboardingChatReturn {
11	  streamMessages: IMessage[];
12	  chatInputValue: string;
13	  isChatSending: boolean;
14	  isTodoExecutionDone: boolean;
15	  setChatInputValue: (value: string) => void;
16	  sendChatMessage: (content: string) => Promise<void>;
17	}
18	
19	/**
20	 * Bridges the chat stage to the global chat stream + store for the welcome
21	 * conversation. Subscribes to `messagesByConversation[conversationId]`,
22	 * exposes input/sending state, and auto-sends `pendingTodoMessage` exactly
23	 * once per (conversation, message) pair when both are present so a user
24	 * clicking "Run now" on a todo lands the message into the live chat.
25	 * Tracks completion of that auto-send via `isTodoExecutionDone` so the page
26	 * can surface a "Continue to GAIA" CTA.
27	 */
28	export function useOnboardingChat(
29	  conversationId: string | null,
30	  pendingTodoMessage?: string | null,
31	): UseOnboardingChatReturn {
32	  const [chatInputValue, setChatInputValue] = useState("");
33	  const [isChatSending, setIsChatSending] = useState(false);
34	  const [isTodoExecutionDone, setIsTodoExecutionDone] = useState(false);
35	
36	  const fetchChatStream = useChatStream();
37	  const activeConversationIdRef = useRef<string | null>(null);
38	  const sentTodoMessagesRef = useRef<Set<string>>(new Set());
39	  const todoExecutionInProgressRef = useRef(false);
40	
41	  // Subscribe to full IMessage[] from the store for this conversation
42	  const streamMessages = useChatStore(
43	    useShallow((state) =>
44	      conversationId
45	        ? (state.messagesByConversation[conversationId] ?? [])
46	        : [],
47	    ),
48	  );
49	
50	  // Set active conversation so useChatStream posts to the right place.
51	  // Re-runs if conversationId changes (e.g. after restart).
52	  useEffect(() => {
53	    if (!conversationId) return;
54	    if (activeConversationIdRef.current === conversationId) return;
55	    useChatStore.getState().setActiveConversationId(conversationId);
56	    activeConversationIdRef.current = conversationId;
57	  }, [conversationId]);
58	
59	  // Detect todo execution completion: isChatSending went true → false while todo was in progress
60	  useEffect(() => {
61	    if (!todoExecutionInProgressRef.current) return;
62	    if (!isChatSending) {
63	      todoExecutionInProgressRef.current = false;
64	      setIsTodoExecutionDone(true);
65	    }
66	  }, [isChatSending]);
67	
68	  const sendChatMessage = useCallback(
69	    async (content: string) => {
70	      const trimmed = content.trim();
71	      if (!trimmed || !conversationId || isChatSending) return;
72	
73	      if (activeConversationIdRef.current !== conversationId) {
74	        useChatStore.getState().setActiveConversationId(conversationId);
75	        activeConversationIdRef.current = conversationId;
76	      }
77	
78	      const userMessageId =
