import { EASE_OUT_QUART } from "../constants/motion";

const WorkflowModal = dynamic(
  () => import("@/features/workflows/components/WorkflowModal"),
  { ssr: false },
);

interface OnboardingWorkflow {
  id?: string;
  title: string;
  description?: string;
  steps?: Array<{ category: string; title?: string; description?: string }>;
  trigger?: {
    type: string;
    cron_expression?: string;
    timezone?: string;
  };
}

interface OnboardingWorkflowCardsProps {
  workflows: OnboardingWorkflow[];
  /** Drop the `ml-10.75` indent — used when the grid is rendered inside an
   *  accordion (where the parent already handles padding). */
  embedded?: boolean;

